import React from 'react'
import { useIntl } from 'gatsby-plugin-intl';

const NotFoundPage = () => (
  <div dangerouslySetInnerHTML={{
    __html: `
    <!DOCTYPE html>
    <html>
    <head>
        <meta http-equiv="Content-type" content="text/html; charset=utf-8" />
        <meta name="viewport"
            content="width=device-width, initial-scale=1, maximum-scale=1, minimum-scale=1, user-scalable=no, viewport-fit=cover">
        <title>
        404 | Page not found
        </title>
        <style type="text/css">
            @font-face {
                font-family: FSEX300;
                src: url(data:application/x-font-ttf;charset=utf-8;base64,) format("truetype"), url(data:image/svg+xml;base64,) format("svg");
                font-style: normal;
                font-weight: 400
            }
    
            html {
                overflow: hidden;
                font-family: FSEX300;
                font-style: normal;
                font-stretch: normal;
                -webkit-user-select: none;
                -moz-user-select: none;
                -ms-user-select: none;
                user-select: none;
                vertical-align: baseline;
                -webkit-tap-highlight-color: transparent;
                -webkit-text-size-adjust: 100%;
                -ms-text-size-adjust: 100%;
                text-size-adjust: 100%;
                color: #fff;
                font-size: 16px
            }
    
            body,
            html {
              background: #0000cd;
                width: 100%;
                height: 100%
            }
    
            body {
                display: -webkit-flex;
                display: flex;
                -webkit-align-items: center;
                align-items: center;
                -webkit-justify-content: center;
                justify-content: center
            }
    
            .container {
                width: 500px;
                text-align: center
            }
    
            p {
                margin: 30px 0;
                text-align: left
            }
    
            a {
                background: #fff;
            }
    
            .title {
                text-transform: full-width;
                background: #ccc;
                color: #0000cd;
                padding: 2px 6px
            }
    
            footer {
                position: fixed;
                left: 0;
                bottom: 0;
                width: 100%;
                color: white;
                text-align: center;
            }
        </style>
    </head>
    
    <body>
    <div class="container">
    <span class="title">
      ${useIntl().formatMessage({ id: "404-title" })}
    </span>
    <p>
        ${useIntl().formatMessage({ id: "404-description1" })}
        <br />
        ${useIntl().formatMessage({ id: "404-description2" })}
        <br />
        <br />
    </p>
    <a href="/" class="title">
    ${useIntl().formatMessage({ id: "404-goBack" })}
    </a>
    <footer>
        <span>
            ${useIntl().formatMessage({ id: "404-credits" })}
        </span>
    </footer>
</div>
    </body>
    
    </html>
    
    `
  }} />
)

export default NotFoundPage
